const item = $input.first();
const input = item.json || {};
const message = input.message || input.edited_message || input.channel_post || input;
const document = message.document || {};
const caption = String(message.caption || '').trim();
const mimeType = String(document.mime_type || '').toLowerCase();
const photos = Array.isArray(message.photo) ? message.photo : [];
const bestPhoto = photos.length ? photos[photos.length - 1] : {};
const originalName = String(document.file_name || (bestPhoto.file_id ? 'telegram-photo.png' : 'remarkable.png'));
const isPngDocument = document.file_id && (mimeType === 'image/png' || originalName.toLowerCase().endsWith('.png'));
const isPhoto = !!bestPhoto.file_id;
if (!isPngDocument && !isPhoto) { return []; }

function extractManualTitle(value) {
  const match = String(value || '').match(/^\s*titel\s*:?\s*(.+)$/i);
  return match ? match[1].trim() : '';
}

function slugify(value) {
  return String(value || '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'remarkable-notitie';
}

const manualTitle = extractManualTitle(caption);
const fallbackTitle = originalName.replace(/\.(png|jpg|jpeg)$/i, '').replace(/[_-]+/g, ' ');
const title = manualTitle || fallbackTitle || 'reMarkable notitie';

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const stamp = now.getFullYear() + '-' + pad(now.getMonth() + 1) + '-' + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes());
const slug = slugify(title);

return [{
  json: {
    imageFileId: isPhoto ? bestPhoto.file_id : document.file_id,
    caption,
    title,
    stamp,
    slug,
    originalName
  }
}];

const item = $input.first();
const binaryMeta = item.binary && item.binary.data;
if (!binaryMeta) {
  throw new Error('Geen PNG-binary gevonden om naar OpenAI te sturen.');
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const pngBase64 = buffer.toString('base64');

const meta = $('Prepare Remarkable PNG Upload').first().json;
const title = meta.title;
const stamp = meta.stamp;
const slug = meta.slug;
const originalPngName = stamp + '-' + slug + '.png';
const mdFileName = stamp + '-' + slug + '.md';

const prompt = [
  'Je analyseert \u00e9\u00e9n PNG-afbeelding van een reMarkable-pagina met handgeschreven notities, schetsen en eventueel ingeplakte afbeeldingen.',
  'Lees handschrift, getypte tekst, pijlen en kaders zo goed mogelijk. Sla losse tekeningen/schetsen/illustraties over: analyseer of beschrijf de inhoud daarvan niet, noteer alleen dat er een tekening aanwezig is.',
  'Gebruik alleen wat zichtbaar is. Verzin geen ontbrekende tekst, meetings of taken.',
  'Doe altijd een beste-poging tot transcriptie, ook bij gekleurde schetsen of rommelig handschrift. Gebruik onzeker/onleesbaar alleen als echt niets te onderscheiden is, en beschrijf het element dan toch zo goed mogelijk in plaats van het over te slaan.',
  '',
  'Notatie systeem:',
  '- Onderstreepte tekst = titel. De EERSTE onderstreepte tekst op de pagina is de hoofdtitel en wordt Markdown H1 (\u00e9\u00e9n #). Elke volgende onderstreepte tekst is een subtitel en wordt Markdown H2 (##).',
  '- Een sterretje bij een regel = werknotitie. Schrijf dit in de markdown als bullet met een liggend streepje "- ", gebruik nooit een letterlijk sterretje.',
  '- Een leeg vierkantje bij een regel = actiepunt.',
  '- Een volledige horizontale streep over de regel = start van een nieuwe sectie zonder eigen titel; bedenk zelf een korte passende sectienaam op basis van de notities die volgen.',
  '',
  'Maak nette Obsidian Markdown in het Nederlands.',
  'Structuur:',
  '1. Begin met een sectie "## Korte samenvatting" gevolgd door een lopende tekst van 2-4 zinnen (geen bullets).',
  '2. Headers per sectie, met de werknotities gegroepeerd op basis van nabijheid op de pagina.',
  '3. Actiepunten: verzamel alle regels met een leeg vierkantje in een aparte sectie. Gebruik voor elke taak exact het formaat - [ ] Sectienaam: actiegerichte zin. Laat de vierkante haakjes nooit weg.',
  '4. Illustraties: geen inhoudelijke analyse. Zet alleen een korte regel per sectie met een tekening, bijvoorbeeld Tekening aanwezig, zie origineel PNG. Ga niet in op vorm, kleur of betekenis.',
  '',
  'Voeg geen HTML, JSON of code fences toe.',
  'Zet geen lege regel tussen een header (# of ##) en de bullet- of taken-lijst die daarna volgt.',
  'Begin niet met bestandsnamen zoals File 16 of page headings. Titelcontext: ' + title
].join('\n');

const body = {
  model: 'gpt-5.4',
  input: [{
    role: 'user',
    content: [
      { type: 'input_image', image_url: 'data:image/png;base64,' + pngBase64, detail: 'high' },
      { type: 'input_text', text: prompt }
    ]
  }],
  temperature: 0.1,
  max_output_tokens: 4000
};

return [{
  json: {
    body,
    title,
    stamp,
    slug,
    originalPngName,
    mdFileName,
    caption: meta.caption
  },
  binary: item.binary
}];

const response = $input.first().json || {};

function extractText(value) {
  if (typeof value.output_text === 'string' && value.output_text.trim()) return value.output_text;
  if (Array.isArray(value.output)) {
    for (const block of value.output) {
      if (Array.isArray(block.content)) {
        for (const part of block.content) {
          if (typeof part.text === 'string' && part.text.trim()) return part.text;
        }
      }
    }
  }
  return '';
}

const meta = $('Prepare PNG Render Command').first().json;
const bodyText = extractText(response).trim();
if (!bodyText) {
  throw new Error('Geen tekst ontvangen van OpenAI voor deze PNG-analyse.');
}

const now = new Date();
const frontmatter = [
  '---',
  'source: "telegram"',
  'type: "remarkable_png"',
  'capture: "remarkable_png_ocr"',
  'status: "inbox"',
  `title: "${meta.title.replace(/"/g, '\\"')}"`,
  `created: "${now.toISOString()}"`,
  `local_time: "${now.toLocaleString('nl-NL')}"`,
  `attachment: "Remarkable/${meta.originalPngName}"`,
  'tags: ["capture", "telegram", "remarkable", "ocr", "notes"]',
  '---',
  ''
].join('\n');

const introSection = [
  `# ${meta.title}`,
  '',
  '## Originele bestanden',
  `- PNG: [[Remarkable/${meta.originalPngName}]]`,
  ''
].join('\n');

const markdown = frontmatter + '\n' + introSection + '\n' + bodyText + '\n';

const actiepunten = [];
const lines = bodyText.split('\n');
for (const line of lines) {
  const match = line.match(/^-\s*\[\s*\]\s*(.+)$/);
  if (match) actiepunten.push(match[1].trim());
}

return [{
  json: {
    markdown,
    mdFileName: meta.mdFileName,
    originalPngName: meta.originalPngName,
    title: meta.title,
    actiepunten
  },
  binary: $('Prepare PNG Render Command').first().binary
}];

const data = $('Build Remarkable PNG OCR Markdown').first().json;
const items = (data.actiepunten || []).map(text => ({ json: { content: text, title: data.title } }));
return items;
